function addSwatches(parent, colors, startX, startY, textColor) {
  const slice = colors.slice(0, SWATCH_COUNT);
  const gap = 10;
  const cols = SWATCH_COUNT;
  const swatchW = Math.floor((FRAME_WIDTH - 48 - gap * (cols - 1)) / cols);
  const swatchH = 40;
  slice.forEach((c, i) => {
    const x = startX + i * (swatchW + gap);
    const y = startY;
    const swatch = figma.createFrame();
    swatch.name = `swatch / ${c.role}`;
    swatch.resize(swatchW, swatchH);
    swatch.x = x;
    swatch.y = y;
    swatch.fills = [{ type: "SOLID", color: hexToRgb(c.hex) }];
    swatch.cornerRadius = 6;
    if (c.hex.toUpperCase() === "#FFFFFF") {
      swatch.strokes = [{ type: "SOLID", color: hexToRgb("#E5E7EB") }];
      swatch.strokeWeight = 1;
    }
    parent.appendChild(swatch);
    const role = createTextSafe(c.role, "Medium", 9, textColor);
    role.x = x;
    role.y = y + swatchH + 3;
    parent.appendChild(role);
    const hexLabel = createTextSafe(c.hex, "Regular", 8, textColor, 0.55);
    hexLabel.x = x;
    hexLabel.y = y + swatchH + 14;
    parent.appendChild(hexLabel);
  });
}
function addTypeScale(parent, scale, startX, startY, textColor) {
  let y = startY;
  scale.slice(0, TYPE_SAMPLE_COUNT).forEach((t) => {
    const sample = createTextSafe(`${t.label} — 아삭하게`, weightToStyle(t.weight), t.size, textColor);
    sample.x = startX;
    sample.y = y;
    parent.appendChild(sample);
    y += t.size * 1.35 + 6;
  });
}

function addMiniHeaderSwatches(parent, colors, startX, startY) {
  const slice = colors.slice(0, SWATCH_COUNT);
  const dotSize = 18;
  const gap = 8;
  slice.forEach((c, i) => {
    const dot = figma.createEllipse();
    dot.name = `swatch dot / ${c.role}`;
    dot.resize(dotSize, dotSize);
    dot.x = startX + i * (dotSize + gap);
    dot.y = startY;
    dot.fills = [{ type: "SOLID", color: hexToRgb(c.hex) }];
    if (c.hex.toUpperCase() === "#FFFFFF") {
      dot.strokes = [{ type: "SOLID", color: hexToRgb("#E5E7EB") }];
      dot.strokeWeight = 1;
    }
    parent.appendChild(dot);
  });
  return dotSize;
}

function addInlineTypeSamples(parent, scale, startX, startY, textColor) {
  const samples = scale.slice(0, TYPE_SAMPLE_COUNT);
  let x = startX;
  samples.forEach((t, i) => {
    const sample = createTextSafe(t.label, weightToStyle(t.weight), Math.min(t.size, 16), textColor);
    sample.x = x;
    sample.y = startY;
    parent.appendChild(sample);
    x += sample.width + (i < samples.length - 1 ? 16 : 0);
    if (i < samples.length - 1) {
      const sep = createTextSafe("·", "Regular", 12, textColor, 0.35);
      sep.x = x - 10;
      sep.y = startY + 2;
      parent.appendChild(sep);
    }
  });
}
