function createRadioOptionGroup(parent, x, y, width, showcase, textColor, candidate) {
  const options = ["Regular", "Large", "Extra"];
  const gap = 10;
  const optH = 48;
  const group = figma.createFrame();
  group.name = "component / option radio group (SCR-004)";
  group.resize(width, optH * options.length + gap * (options.length - 1));
  group.x = x;
  group.y = y;
  group.fills = [];
  parent.appendChild(group);

  const primaryHex =
    candidate.buttonPrimary.fill ||
    (candidate.colors[0] && candidate.colors[0].hex) ||
    "#16A34A";

  options.forEach((label, i) => {
    const selected = i === 0;
    const row = figma.createFrame();
    row.name = `radio / ${label}${selected ? " · selected" : ""}`;
    row.resize(width, optH);
    row.x = 0;
    row.y = i * (optH + gap);
    row.cornerRadius = Math.max(8, (showcase.cardRadius || 16) - 4);
    row.fills = [{ type: "SOLID", color: hexToRgb(showcase.cardSurface || "#FFFFFF") }];
    row.strokes = [
      {
        type: "SOLID",
        color: hexToRgb(selected ? primaryHex : showcase.ctaBarStroke || "#E5E7EB"),
      },
    ];
    row.strokeWeight = selected ? 2 : 1;
    group.appendChild(row);

    const radio = figma.createEllipse();
    radio.name = "radio circle";
    radio.resize(22, 22);
    radio.x = 16;
    radio.y = 13;
    if (selected) {
      radio.fills = [{ type: "SOLID", color: hexToRgb(primaryHex) }];
      radio.strokes = [];
    } else {
      radio.fills = [];
      radio.strokes = [{ type: "SOLID", color: hexToRgb(showcase.ctaBarStroke || "#D1D5DB") }];
      radio.strokeWeight = 2;
    }
    row.appendChild(radio);

    if (selected) {
      const dot = figma.createEllipse();
      dot.name = "radio dot";
      dot.resize(8, 8);
      dot.x = 23;
      dot.y = 20;
      dot.fills = [{ type: "SOLID", color: hexToRgb(candidate.buttonPrimary.text || "#FFFFFF") }];
      row.appendChild(dot);
    }

    const lbl = createTextSafe(label, selected ? "Semi Bold" : "Medium", 15, textColor);
    lbl.x = 52;
    lbl.y = 14;
    row.appendChild(lbl);

    const priceDelta = i === 0 ? "+₩0" : i === 1 ? "+₩1,000" : "+₩2,000";
    const delta = createTextSafe(priceDelta, "Regular", 13, textColor, 0.5);
    delta.x = width - 72;
    delta.y = 16;
    row.appendChild(delta);
  });
  return group;
}

