function buildComponentsShowcase(parent, candidate, startY, textColor) {
  const pad = 24;
  const contentW = FRAME_WIDTH - pad * 2;
  const colGap = 16;
  const colW = Math.floor((contentW - colGap) / 2);
  const showcase = candidate.showcase || {};
  let y = startY;

  createHeroStrip(parent, pad, y, contentW, candidate, showcase, textColor);
  y += 72 + 16;

  createTabBar(parent, pad, y, contentW, showcase, textColor);
  y += 44 + 16;

  createMenuPhotoCard(parent, pad, y, contentW, showcase, textColor, candidate);
  y += 228 + 16;

  createHorizontalMenuCard(parent, pad, y, colW, showcase, textColor, candidate);
  createSoldOutMiniCard(parent, pad + colW + colGap, y, colW, showcase, textColor, candidate);
  y += 96 + 16;

  createOptionChipRow(parent, pad, y, contentW, showcase, textColor);
  y += 48 + 16;

  const radioH = 48 * 3 + 10 * 2;
  createRadioOptionGroup(parent, pad, y, colW, showcase, textColor, candidate);
  createQuantityStepper(parent, pad + colW + colGap, y, colW, showcase, textColor, candidate);
  y += radioH + 16;

  const listBg = figma.createFrame();
  listBg.name = "component / list group";
  listBg.resize(contentW, 136);
  listBg.x = pad;
  listBg.y = y;
  listBg.cornerRadius = showcase.cardRadius >= 16 ? 14 : 10;
  listBg.fills = [{ type: "SOLID", color: hexToRgb(showcase.cardSurface || "#FFFFFF") }];
  listBg.strokes = [{ type: "SOLID", color: hexToRgb(showcase.ctaBarStroke || "#E5E7EB") }];
  listBg.strokeWeight = 1;
  applyDropShadow(listBg, { opacity: 0.06, y: 3, radius: 12 });
  parent.appendChild(listBg);

  createListRow(listBg, 0, 0, contentW, showcase, textColor, "매장 설정", "영업 시간 · 알림 · 프린터", true);
  createListRow(listBg, 0, 68, contentW, showcase, textColor, "결제 · 영수증", "카드 · 현금 · 간편결제", false);
  y += 136 + 16;

  createPaymentMethodRow(parent, pad, y, colW, showcase, textColor, candidate);
  createSuccessToast(parent, pad + colW + colGap, y, colW, candidate, showcase, textColor);
  y += 72 + 16;

  createBottomCTABar(parent, pad, y, contentW, candidate, showcase, textColor);
}
function buildCandidateFrame(candidate, index) {
  const frame = figma.createFrame();
  frame.name = candidate.frameName;
  frame.resize(FRAME_WIDTH, FRAME_HEIGHT);
  frame.x = index * (FRAME_WIDTH + FRAME_GAP);
  frame.y = 0;
  frame.fills = [{ type: "SOLID", color: hexToRgb(candidate.bg) }];
  frame.clipsContent = true;
  const pad = 24;
  const textEntry = candidate.colors.find((c) => c.role === "Text" || c.role.startsWith("Text"));
  const textColor = textEntry ? textEntry.hex : "#1F2937";
  const title = createTextSafe(candidate.frameName, "Bold", 20, textColor);
  title.x = pad;
  title.y = pad;
  frame.appendChild(title);
  const sub = createTextSafe(candidate.subtitle, "Regular", 11, textColor, 0.65);
  sub.x = pad;
  sub.y = pad + 26;
  frame.appendChild(sub);
  addMiniHeaderSwatches(frame, candidate.colors, pad, pad + 48);
  addInlineTypeSamples(frame, candidate.typeScale, pad + 100, pad + 50, textColor);
  const spec = createTextSafe("834×2400 · touch ≥44px · Pretendard", "Regular", 9, textColor, 0.4);
  spec.x = pad;
  spec.y = pad + 72;
  frame.appendChild(spec);
  addSectionLabel(frame, "Components", pad, pad + 92, 13, textColor);
  buildComponentsShowcase(frame, candidate, pad + 112, textColor);
  return frame;
}
async function run() {
  await figma.loadAllPagesAsync();
  figma.notify("페이지 로드 완료 · DS 후보 생성 중…", { timeout: 5000 });
  try {
    figma.root.setRelaunchData({ create: "" });
  } catch (err) {
    console.warn("setRelaunchData 건너뜀 (manifest id 확인):", err.message || err);
  }
  const fontWarnings = await loadFonts();
  if (fontWarnings.length) {
    console.warn("폰트 경고:\n" + fontWarnings.join("\n"));
  }
  await loadMenuImages();
  if (Object.keys(menuImageCache).length === 0) {
    console.warn(
      "메뉴 사진 없음 — embed_menu_images.py 실행 후 플러그인 재등록. 그라데이션 placeholder로 대체합니다."
    );
  }
  const { page, log, warnings } = resolveUserFlowPage();
  if (log.length) console.log("=== 페이지 해석 ===\n" + log.join("\n"));
  if (warnings.length) console.warn("페이지 경고:\n" + warnings.join("\n"));
  try {
    await figma.setCurrentPageAsync(page);
  } catch (err) {
    console.warn("currentPage 설정 실패:", err.message || err);
  }
  removeExistingDsFrames(page);
  const created = [];
  for (let i = 0; i < CANDIDATES.length; i++) {
    try {
      const frame = buildCandidateFrame(CANDIDATES[i], i);
      page.appendChild(frame);
      created.push(CANDIDATES[i].frameName);
    } catch (err) {
      const msg = err && err.message ? err.message : String(err);
      console.error(`프레임 생성 실패 (${CANDIDATES[i].frameName}):`, msg);
      throw new Error(`${CANDIDATES[i].frameName} 생성 실패: ${msg}`);
    }
  }
  if (created.length > 0) {
    try {
      figma.viewport.scrollAndZoomIntoView(
        page.children.filter((c) => created.includes(c.name))
      );
    } catch (err) {
      console.warn("뷰포트 이동 실패:", err.message || err);
    }
  }
  const summary = `DS 후보 ${created.length}개 생성: ${created.join(" · ")}`;
  const webNote = " (Desktop 권장 · 콘솔 Ctrl+Shift+I)";
  if (warnings.length > 0) {
    figma.notify(warnings[0] + " · " + summary + webNote, { error: true, timeout: 15000 });
  } else if (fontWarnings.length > 0) {
    figma.notify(summary + " · 일부 폰트 스타일 누락 (Regular로 대체)" + webNote, {
      timeout: 12000,
    });
  } else {
    figma.notify(summary + webNote, { timeout: 12000 });
  }
}
/** 즉시 피드백 + 타임아웃 폴백 + try/catch로 무응답·조용한 실패 방지 */
function main() {
  figma.notify("플러그인 시작…", { timeout: 5000 });
  const frameCount = CANDIDATES.length;
  const slowTimer = setTimeout(function () {
    figma.notify(
      `처리 중… 프레임 ${frameCount}개 생성에 20~45초 걸릴 수 있습니다. 콘솔(Ctrl+Shift+I)을 열어 두세요.`,
      { timeout: 15000 }
    );
  }, 8000);
  run()
    .catch(function (err) {
      console.error("Create DS Candidates 오류:", err);
      const msg = err && err.message ? err.message : String(err);
      figma.notify("플러그인 오류: " + msg, { error: true, timeout: 20000 });
    })
    .finally(function () {
      clearTimeout(slowTimer);
      figma.closePlugin();
    });
}
main();
